package services

import models.Order
import javax.inject._
import scala.concurrent.{ExecutionContext, Future}
import slick.jdbc.JdbcProfile
import slick.jdbc.PostgresProfile.api._

@Singleton
class OrderService @Inject()(db: Database)(implicit ec: ExecutionContext) {

  def getOrderByIdAndUser(orderId: Long, userId: Long): Future[Option[Order]] = {
    val query = sql"SELECT * FROM orders WHERE id = $orderId AND user_id = $userId".as[Order]
    db.run(query.headOption)
  }
}

